// 检查当前 Word 文档中的表格数量
var doc = Application.ActiveDocument;
return {
  tableCount: doc.Tables ? doc.Tables.Count : 0,
  hasTables: doc.Tables && doc.Tables.Count > 0
};

// 遍历所有表格，将"同上"替换为上方单元格内容，"同左"替换为左侧单元格内容
var doc = Application.ActiveDocument;
var tables = doc.Tables;
var totalReplacements = 0;

for (var t = 1; t <= tables.Count; t++) {
  var table = tables.Item(t);
  var rows = table.Rows.Count;
  var cols = table.Columns.Count;

  for (var r = 1; r <= rows; r++) {
    for (var c = 1; c <= cols; c++) {
      var cell = table.Cell(r, c);
      var range = cell.Range;
      var text = range.Text.replace(/\r\n$/, ''); // 去除末尾段落标记

      if (text === '同上' && r > 1) {
        var aboveCell = table.Cell(r - 1, c);
        var aboveText = aboveCell.Range.Text.replace(/\r\n$/, '');
        range.Text = aboveText;
        totalReplacements++;
      } else if (text === '同左' && c > 1) {
        var leftCell = table.Cell(r, c - 1);
        var leftText = leftCell.Range.Text.replace(/\r\n$/, '');
        range.Text = leftText;
        totalReplacements++;
      }
    }
  }
}

return { success: true, replacements: totalReplacements };
